// Packet Fabric -- advect each packet along an assigned link curve, recycle at the end.
// uFlow  = (flowSpeed, linkCount, curveAmount, time)
// uClock = (ptpRate, fieldScale, streams, jitter)
// Uniforms are AUTO-declared from the Vectors page -- do NOT redeclare here.

float hash11(float p){ return fract(sin(p*127.1)*43758.5453); }
vec3  hash31(float p){ return fract(sin(vec3(p*127.1, p*311.7, p*74.7))*43758.5453)*2.0-1.0; }

// A node anchor on a coarse ring/grid in the field, indexed by an integer id.
vec3 nodeAnchor(float n, float scale){
    vec3 h = hash31(n*13.0 + 1.0);
    // spread nodes mostly along X (signal flow l->r), with Y/Z depth scatter
    return vec3(h.x*1.4*scale, h.y*0.7*scale, h.z*0.9*scale);
}

void main(){
    const uint id = TDIndex();
    if(id >= TDNumElements()) return;

    float t        = uFlow.w;
    float speed    = uFlow.x;
    float linkN    = max(2.0, uFlow.y);
    float curve    = uFlow.z;
    float scale    = uClock.y;
    float jitter   = uClock.w;

    float pid = float(id);

    // assign this packet to a link (a pair of node anchors) deterministically
    float link    = floor(mod(pid, linkN));
    float srcNode = floor(mod(link*2.0,  linkN+7.0));
    float dstNode = floor(mod(link*2.0+1.0, linkN+11.0));
    vec3  A = nodeAnchor(srcNode, scale) + vec3(-1.6*scale, 0.0, 0.0); // senders to the left
    vec3  B = nodeAnchor(dstNode, scale) + vec3( 1.6*scale, 0.0, 0.0); // receivers to the right

    // a gentle control point so the link bows (fiber slack), perpendicular-ish
    vec3  mid = mix(A, B, 0.5);
    vec3  bow = vec3(0.0, (hash11(link*7.3)*2.0-1.0)*1.1, (hash11(link*3.1)*2.0-1.0)*0.8) * curve;
    vec3  C   = mid + bow;

    // per-packet phase along the link: a fixed offset + continuous travel
    float jit   = (hash11(pid*1.7)*2.0-1.0) * 0.08 * jitter;     // tiny stagger so packets don't lockstep-march
    float s     = fract(hash11(pid*9.13) + (t*speed*(0.6+0.5*hash11(pid*4.2))) + jit);

    // quadratic Bezier A->C->B (smooth curved link)
    float u  = 1.0 - s;
    vec3 pos = u*u*A + 2.0*u*s*C + s*s*B;

    P[id] = pos;
}

// Packet Fabric -- per-packet stream color + PTP sync flash. (render side branch)
// uClock = (ptpRate, time, streams, pulseStrength)
// New attributes Color (vec4) and PointScale (float) come from the Attr sequence.
float hash11(float p){ return fract(sin(p*127.1)*43758.5453); }

void main(){
    const uint id = TDIndex();
    if(id >= TDNumElements()) return;

    vec3 pos = TDIn_P(0, id);
    float pid = float(id);

    float streams = max(1.0, uClock.z);
    float klass   = floor(mod(pid, streams));   // 0=video,1=audio,2=ancillary

    vec3 cyan  = vec3(0.00, 0.90, 1.00);   // video essence
    vec3 green = vec3(0.22, 1.00, 0.42);   // audio essence
    vec3 amber = vec3(1.00, 0.69, 0.00);   // ancillary data
    vec3 col = (klass < 0.5) ? cyan : (klass < 1.5) ? green : amber;

    // white-hot core: lift toward white, palette carries the mid-glow
    col = mix(col, vec3(1.0), 0.35);

    // PTP grandmaster pulse: a steady beat all packets flash to, in lockstep.
    float rate  = max(0.05, uClock.x);
    float beat  = fract(uClock.y * rate);
    float flash = pow(max(0.0, 1.0 - beat*3.0), 3.0);   // sharp decay after each tick
    float pulse = 1.0 + uClock.w * flash;

    // base brightness low so additive blending doesn't fully wash out; bloom carries glow
    Color[id]      = vec4(col * (0.45 * pulse), 1.0);
    PointScale[id] = 0.8 + 0.7*flash;   // packets swell on the sync beat
}

out vec4 fragColor;
void main(){
    vec2 uv = vUV.st * 2.0 - 1.0;
    float r = length(uv);
    float a = smoothstep(1.0, 0.05, r);   // bright round core, soft falloff edge
    a = pow(a, 1.5);
    fragColor = vec4(vec3(a), 1.0);
}

// Static IP-fabric background: dim cool-gray nodes + faint links + depth haze + grain.
uniform vec4 uFab;   // x=linkCount, y=fieldScale, z=slowTime, w=ptpRate
out vec4 fragColor;

float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }

// distance from point p to segment a-b
float segDist(vec2 p, vec2 a, vec2 b){
    vec2 pa = p-a, ba = b-a;
    float h = clamp(dot(pa,ba)/dot(ba,ba), 0.0, 1.0);
    return length(pa - ba*h);
}

void main(){
    vec2 uv = vUV.st;
    float aspect = uTDOutputInfo.res.z / uTDOutputInfo.res.w;
    vec2 p = (uv - 0.5); p.x *= aspect;

    // near-black charcoal ground with a faint center lift
    vec3 col = mix(vec3(0.012,0.014,0.018), vec3(0.03,0.035,0.045), 1.0 - length(p));

    float linkN = clamp(uFab.x, 4.0, 24.0);
    vec3 fiber = vec3(0.0);
    // faint structural links between deterministic node anchors
    const int MAXL = 24;
    for(int i=0;i<MAXL;i++){
        if(float(i) >= linkN) break;
        float fi = float(i);
        vec2 a = (vec2(hash21(vec2(fi,1.0)), hash21(vec2(fi,2.0)))-0.5)*vec2(1.9,1.1);
        vec2 b = (vec2(hash21(vec2(fi,3.0)), hash21(vec2(fi,4.0)))-0.5)*vec2(1.9,1.1);
        a.x -= 0.5; b.x += 0.5;   // sender side / receiver side
        float d = segDist(p, a, b);
        fiber += vec3(0.10,0.13,0.16) * smoothstep(0.012, 0.0, d) * 0.5;
        // node glows at the endpoints (cool gray, slow twinkle)
        float tw = 0.7 + 0.3*sin(uFab.z*6.2831 + fi*2.0);
        fiber += vec3(0.12,0.16,0.20) * smoothstep(0.06,0.0,length(p-a)) * tw;
        fiber += vec3(0.12,0.16,0.20) * smoothstep(0.06,0.0,length(p-b)) * tw;
    }
    col += fiber;

    // depth haze: dim the edges into a vanishing field
    col *= mix(1.0, 0.5, smoothstep(0.4, 1.1, length(p)));

    // film grain to kill banding on the dark gradient at booth scale
    float g = hash21(uv*uTDOutputInfo.res.zw + uFab.z*100.0) - 0.5;
    col += g * 0.012;

    fragColor = vec4(max(col, 0.0), 1.0);
}

// Two-pass-in-one bright-pass + radial blur bloom added back over the source.
uniform vec4 uBloom;   // x=bloomStrength, y=threshold
out vec4 fragColor;

void main(){
    vec2 uv = vUV.st;
    vec2 texel = uTDOutputInfo.res.xy;   // 1/w, 1/h
    vec3 src = texture(sTD2DInputs[0], uv).rgb;

    float thr = uBloom.y;
    vec3 sum = vec3(0.0);
    float wsum = 0.0;
    // bounded separable-ish gaussian sample of the bright pass (constant taps)
    const int R = 6;
    for(int x=-R; x<=R; x++){
        for(int y=-R; y<=R; y++){
            vec2 o = vec2(float(x), float(y));
            float w = exp(-dot(o,o)/18.0);
            vec3 s = texture(sTD2DInputs[0], uv + o*texel*2.0).rgb;
            vec3 bright = max(s - thr, 0.0);   // bright pass
            sum += bright * w;
            wsum += w;
        }
    }
    vec3 bloom = sum / max(wsum, 1e-4);
    vec3 col = src + bloom * uBloom.x;

    // faint scanline overlay for broadcast authenticity
    float scan = 0.97 + 0.03*sin(uv.y * uTDOutputInfo.res.w * 3.14159);
    col *= scan;

    fragColor = vec4(col, 1.0);
}
